{:version=>3, :sections=>[{:offset=>{:line=>0, :column=>0}, :map=>{:version=>3, :sourceRoot=>"", :sources=>["bcdice/game_system/WoW.rb"], :sourcesContent=>["# frozen_string_literal: true\n\nmodule BCDice\n  module GameSystem\n    class WoW < Base\n      # ゲームシステムの識別子\n      ID = 'WoW'\n\n      # ゲームシステム名\n      NAME = 'ワンダーオブワンダラー'\n\n      # ゲームシステム名の読みがな\n      SORT_KEY = 'わんたあおふわんたらあ'\n\n      # ダイスボットの使い方\n      HELP_MESSAGE = <<~INFO_MESSAGE_TEXT\n        行為判定 nWW12@s#f<=x\n        n: ダイス数\n        @s = 大成功値（省略可：デフォルトは1）\n        #f = 大失敗値（省略可：デフォルトは12）\n        x = 目標値（省略可：デフォルトは6）\n        例）1WW12 5WW12<=6 6WW12@5#3<=7+1\n\n        ランダムギフトガチャ表 GG\n        ランダムギフトガチャ表（アルファベット指定） GGx 例）GGA GGB\n\n        ファンブル表 FT\n      INFO_MESSAGE_TEXT\n\n      register_prefix('\\d*WW12', 'GG', 'GGA', 'GGB', 'GGC', 'GGD', 'GGE', 'GGF', 'GGG', 'GGH', 'FT')\n\n      TABLES = {\n        'A' => [\n          '演者の声', '言いくるめ', '誤魔化し', '代弁者', '腕利き弁護人', '魔性', '魔術', '魔法的物理', '誤り指摘', '専門知識', '理力増幅', '協力的な有識者'\n        ],\n        'B' => [\n          '百科全書', '地道な下調べ', '思い…出した！', '目星', 'ハッキング', '再考察', '迷探偵', '逆転の発想', '炯眼', '安楽椅子探偵', '密室トリック解明', '丁寧な処置'\n        ],\n        'C' => [\n          '慈愛', 'クイックヒール', 'エリアヒール', 'クリアランス', '俯瞰視点', 'パターン化', '瞬時看破', '警鐘', '賢者の瞳', '千里眼', '危険感知', 'リバーサル'\n        ],\n        'D' => [\n          '転禍為福', '受け身', '九死に一生', '軽業', 'バックドア', '着服', '闇に隠れる', '変装', '証拠隠滅', 'サポート', '技師の指', '妨害'\n        ],\n        'E' => [\n          'ゴッドハンド', '生存者の切り札', '狙撃', 'プラチナ免許', 'ドライバーズ・ハイ', '相乗り', '愛車／愛馬', 'ビーストフレンズ', 'ドゥ・ライブ', 'カツアゲ', 'マッドドッグ', '目の上の瘤'\n        ],\n        'F' => [\n          '叱咤激励', 'ふいに見せた優しさ', 'スゴ味', '達人', '必殺技', '二刀流', '急所狙い', 'ジャンプショット', 'パルクール', '疾風怒濤', 'スパート', '走為上'\n        ],\n        'G' => [\n          'ヒット＆アウェイ', 'ウーバー', '割れもの注意', 'もしもの備え', 'アブダクション', '追加機材', '自在配送', '不屈の精神', '防壁', '心頭滅却', '三時間しか寝てない', 'βエンドルフィン'\n        ],\n        'H' => [\n          '怒髪天', '頭の体操', '精神統一', 'リトルラック', 'いいね！', '幻視', '慎重性', 'バレットストッパー', '褪せぬ想い', 'アピール上手', '土俵際の魔術師', '真実の愛'\n        ],\n        'FT' => [\n          '何も起きなかった！　ラッキー（？）',\n          'ランダムに武器または防具が外れる。該当箇所に何も装備していなければ1点のダメージ（軽減無効）を受ける。',\n          'GMの指定したLOVEの【深度】が1増加する。誰かに対するLOVEを新規取得させても良い。',\n          'GMの指定したハンドアウト1つの強度が［自身のソウルLV／2］増加する。',\n          '1点のダメージ（軽減無効）を受ける。',\n          'プレイス内のPCが所持している消耗品からGMが1つ指定し、破壊する。破壊したくない場合、かわりに自身のHPを最大値の1／3（切り捨て）減らす。',\n          '不調強度［自身のソウルLV／2］のランダムな不調を受ける。',\n          'ファンブル表を2回振る。この効果は判定につき1度までで、以降は1点のダメージ（軽減無効）を受ける。',\n          'ランダムなLOVEの【深度】が1減少する。',\n          'ランダムなLOVEの【エモ】が2増加する。',\n          'トラブルが発生する。ランダムトラブル表を使用し、場にトラブルのハンドアウトを追加する。',\n          'ランダムなギフト1つのMPが0になる。'\n        ]\n      }.freeze\n\n      def eval_game_system_specific_command(command)\n        case command\n        when 'GG'\n          return roll_gg\n        when /^GG([A-H])$/\n          return roll_table(::Regexp.last_match(1))\n        when 'FT'\n          return roll_fumble_table\n        else\n          return roll_wow(command)\n        end\n      end\n\n      private\n\n      def roll_gg\n        dice_results = @randomizer.roll_barabara(2, 12)\n        first_roll = dice_results[0]\n        second_roll = dice_results[1]\n\n        if first_roll >= 9\n          return \"GG ＞ 自由（アルファベットを決めてGGXを振る）\"\n        end\n\n        alphabet = (64 + first_roll).chr\n        table = TABLES[alphabet]\n        return \"ランダムギフトガチャ \#{alphabet}-\#{second_roll} ＞ \#{table[second_roll - 1]}\"\n      end\n\n      def roll_table(alphabet)\n        table = TABLES[alphabet]\n        dice_result = @randomizer.roll_once(12)\n        return \"ランダムギフトガチャ \#{alphabet}-\#{dice_result} ＞ \#{table[dice_result - 1]}\"\n      end\n\n      def roll_fumble_table\n        dice_result = @randomizer.roll_once(12)\n        table = TABLES['FT']\n        return \"FT(\#{dice_result}) ＞ \#{table[dice_result - 1]}\"\n      end\n\n      def roll_wow(command)\n        # コマンドの解析\n        m = /^(\\d+)WW12(?:@(\\d+))?(?:#(\\d+))?(?:<=(\\d+))?$/.match(command)\n        return nil unless m\n\n        num_dice = m[1].to_i # 振るダイスの数\n        critical_success_value = m[2] ? m[2].to_i : 1 # 大成功の値（デフォルトは1）\n        critical_fail_value = m[3] ? m[3].to_i : 12 # 大失敗の値（デフォルトは12）\n        success_threshold = m[4] ? m[4].to_i : 6 # 成功の閾値（デフォルトは6）\n\n        if m[4].nil?\n          command_with_defaults = \"\#{m[1]}WW12<=\#{success_threshold}\"\n        else\n          command_with_defaults = command\n        end\n\n        # ダイスを振る\n        dice_results = @randomizer.roll_barabara(num_dice, 12)\n\n        # 出目を分類\n        critical_success = dice_results.count { |r| r <= critical_success_value } # 大成功の数\n        critical_fail = dice_results.count { |r| r >= critical_fail_value } # 大失敗の数\n        normal_success = dice_results.count { |r| (r > critical_success_value) && (r <= success_threshold) && r < critical_fail_value }\n\n        critical_success_first = critical_success\n        critical_fail_first = critical_fail\n\n        # 大成功と大失敗の相殺\n        offset = [critical_success, critical_fail].min\n        critical_success -= offset\n        critical_fail -= offset\n\n        # 成功数とファンブルの判定\n        successes = normal_success + (critical_success * 2)\n        is_fumble = critical_fail > 0\n\n        # 結果をBCDICE::Resultで構造化\n        BCDice::Result.new.tap do |r|\n          r.text = \"(\#{command_with_defaults}) ＞ [\#{dice_results.join(',')}] ＞ 成功数\#{successes}（大成功\#{critical_success_first}個、大失敗\#{critical_fail_first}個）\#{is_fumble ? ' ＞ ファンブル！' : ''}\"\n          r.critical = critical_success > 0\n          r.fumble = is_fumble\n          r.success = successes > 0 && !is_fumble  # 成功数が0より大きく、ファンブルがない場合に成功\n          r.failure = successes == 0 || is_fumble  # 成功数が0、またはファンブルがある場合に失敗\n        end\n      end\n    end\n  end\nend\n"], :names=>["<main>", "<module:BCDice>", "<module:GameSystem>", "<class:WoW>", "self", "register_prefix", "freeze", "eval_game_system_specific_command", "command", "$ret_or_1", "roll_gg", "roll_table", "Regexp", "last_match", "1", "roll_fumble_table", "roll_wow", "private", "dice_results", "@randomizer", "roll_barabara", "2", "12", "first_roll", "[]", "0", "second_roll", ">=", "9", "alphabet", "+", "64", "chr", "table", "TABLES", "-", "dice_result", "roll_once", "m", "match", "num_dice", "to_i", "critical_success_value", "critical_fail_value", "3", "success_threshold", "4", "6", "nil?", "command_with_defaults", "critical_success", "count", "block in roll_wow", "r", "block (2 levels) in roll_wow", "<=", "critical_fail", "normal_success", "$ret_or_2", ">", "<", "critical_success_first", "critical_fail_first", "offset", "min", "successes", "*", "is_fumble", "tap", "BCDice::Result", "BCDice", "new", "text=", "join", "critical=", "fumble=", "success=", "!", "failure=", "==", "Base"], :mappings=>"AAAAA,2BAAAA;EAAAA;;EAEAA,OAAAC;EAAAA;;IAAAA;;IACEA,OAAAC;IAAAA;;MAAAA;;MACEA,OAAAC;MAAAA;;QAAAA;;AAAAA;;QAEE,8BAAKA,KAAL;QAGA,gCAAOA,aAAP;QAGA,oCAAWA,aAAX;QAGA,wCACNA,qBADqB,GAErBA,WAFqB,GAGrBA,0BAHqB,GAIrBA,2BAJqB,GAKrBA,wBALqB,GAMrBA,mCANqB,GAOrBA,IAPqB,GAQrBA,kBARqB,GASrBA,wCATqB,GAUrBA,IAVqB,GAWrBA,aAXM;QAcAC,IAAAC,iBAAAA,CAAgBF,UAAhB,EAA2BA,IAA3B,EAAiCA,KAAjC,EAAwCA,KAAxC,EAA+CA,KAA/C,EAAsDA,KAAtD,EAA6DA,KAA7D,EAAoEA,KAApE,EAA2EA,KAA3E,EAAkFA,KAAlF,EAAyFA,IAAzFE;QAEA,kCAAS,wDAAA,KACA,CACLF,MADK,EACGA,OADH,EACYA,MADZ,EACoBA,KADpB,EAC2BA,QAD3B,EACqCA,IADrC,EAC2CA,IAD3C,EACiDA,OADjD,EAC0DA,MAD1D,EACkEA,MADlE,EAC0EA,MAD1E,EACkFA,SADlF,CADA,EAAA,KAIA,CACLA,MADK,EACGA,QADH,EACaA,SADb,EACwBA,IADxB,EAC8BA,OAD9B,EACuCA,KADvC,EAC8CA,KAD9C,EACqDA,OADrD,EAC8DA,IAD9D,EACoEA,QADpE,EAC8EA,UAD9E,EAC0FA,OAD1F,CAJA,EAAA,KAOA,CACLA,IADK,EACCA,SADD,EACYA,QADZ,EACsBA,QADtB,EACgCA,MADhC,EACwCA,OADxC,EACiDA,MADjD,EACyDA,IADzD,EAC+DA,MAD/D,EACuEA,KADvE,EAC8EA,MAD9E,EACsFA,OADtF,CAPA,EAAA,KAUA,CACLA,MADK,EACGA,KADH,EACUA,OADV,EACmBA,IADnB,EACyBA,OADzB,EACkCA,IADlC,EACwCA,OADxC,EACiDA,IADjD,EACuDA,MADvD,EAC+DA,MAD/D,EACuEA,MADvE,EAC+EA,IAD/E,CAVA,EAAA,KAaA,CACLA,QADK,EACKA,SADL,EACgBA,IADhB,EACsBA,QADtB,EACgCA,WADhC,EAC6CA,KAD7C,EACoDA,OADpD,EAC6DA,UAD7D,EACyEA,QADzE,EACmFA,MADnF,EAC2FA,QAD3F,EACqGA,OADrG,CAbA,EAAA,KAgBA,CACLA,MADK,EACGA,WADH,EACgBA,KADhB,EACuBA,IADvB,EAC6BA,KAD7B,EACoCA,KADpC,EAC2CA,MAD3C,EACmDA,UADnD,EAC+DA,OAD/D,EACwEA,MADxE,EACgFA,MADhF,EACwFA,KADxF,CAhBA,EAAA,KAmBA,CACLA,UADK,EACOA,MADP,EACeA,QADf,EACyBA,QADzB,EACmCA,SADnC,EAC8CA,MAD9C,EACsDA,MADtD,EAC8DA,OAD9D,EACuEA,IADvE,EAC6EA,MAD7E,EACqFA,WADrF,EACkGA,UADlG,CAnBA,EAAA,KAsBA,CACLA,KADK,EACEA,MADF,EACUA,MADV,EACkBA,QADlB,EAC4BA,MAD5B,EACoCA,IADpC,EAC0CA,KAD1C,EACiDA,WADjD,EAC8DA,OAD9D,EACuEA,QADvE,EACiFA,SADjF,EAC4FA,MAD5F,CAtBA,EAAA,MAyBC,CACNA,mBADM,EAENA,qDAFM,EAGNA,+CAHM,EAINA,sCAJM,EAKNA,oBALM,EAMNA,yEANM,EAONA,+BAPM,EAQNA,mDARM,EASNA,uBATM,EAUNA,uBAVM,EAWNA,6CAXM,EAYNA,qBAZM,CAzBD,EAuCRG,QAAAA,CAAAA,CAvCD;;AAyCAC,QAAAA,iDAAAA,6CAAsCC,OAAtCD;AAAAA,UAAAA;;UAEE,IAAA,QAAKA,IAAL,EADAE,CAAAA,YAAKD,OAALC,CACA,CAAA;YACE,OAAOL,IAAAM,SAAAA,CAAAA;UADT,OAEA,IAAA,QAAK,aAAL,EA5ER,SA4EQ,CAAA;YACE,OAAON,IAAAO,YAAAA,CAAWC,aAAQC,YAAAA,CAAYC,CAAZD,CAAnBF;UADT,OAEA,IAAA,QAAKJ,IAAL,EA9ER,SA8EQ,CAAA;YACE,OAAOH,IAAAW,mBAAAA,CAAAA;UADT;YAGE,OAAOX,IAAAY,UAAAA,CAASR,OAATQ;UAHT;QANFT,CAAAA;QAaAH,IAAAa,SAAAA,CAAAA;;AAEAP,QAAAA,uBAAAA,mBAAAA;AAAAA,UAAAA;;;UACEQ,eAAeC,eAAWC,eAAAA,CAAeC,CAA1B,EAA6BC,EAAlBF;UAC1BG,aAAaL,YAAYM,OAAAA,CAACC,CAADD;UACzBE,cAAcR,YAAYM,OAAAA,CAACV,CAADU;UAE1B,IAAA,QAAcG,OAAXJ,UAAWI,EAAGC,CAAHD,CAAd,CAAA;YACE,OAAOjB;UADT;UAIAmB,WAAeC,SAAHC,EAAGD,EAAEP,UAAFO,CAAaE,KAAAA,CAAAA;UAC5BC,QAAQC,YAAMV,OAAAA,CAACK,QAADL;UACd,OAAQd,aAAD,GAAA,CAAcmB,QAAd,CAAA,GAAuBnB,GAAvB,GAAA,CAA0BgB,WAA1B,CAAA,GAAsChB,KAAtC,GAAA,CAA2CuB,KAAKT,OAAAA,CAAaW,UAAZT,WAAYS,EAAErB,CAAFqB,CAAbX,CAAhD;QAXTd,CAAAA;;AAcAC,QAAAA,0BAAAA,sBAAekB,QAAflB;AAAAA,UAAAA;;;UACEsB,QAAQC,YAAMV,OAAAA,CAACK,QAADL;UACdY,cAAcjB,eAAWkB,WAAAA,CAAWf,EAAXe;UACzB,OAAQ1B,aAAD,GAAA,CAAckB,QAAd,CAAA,GAAuBlB,GAAvB,GAAA,CAA0ByB,WAA1B,CAAA,GAAsCzB,KAAtC,GAAA,CAA2CsB,KAAKT,OAAAA,CAAaW,UAAZC,WAAYD,EAAErB,CAAFqB,CAAbX,CAAhD;QAHTb,CAAAA;;AAMAI,QAAAA,iCAAAA,6BAAAA;AAAAA,UAAAA;;;UACEqB,cAAcjB,eAAWkB,WAAAA,CAAWf,EAAXe;UACzBJ,QAAQC,YAAMV,OAAAA,CAACT,IAADS;UACd,OAAQT,KAAD,GAAA,CAAMqB,WAAN,CAAA,GAAkBrB,MAAlB,GAAA,CAAwBkB,KAAKT,OAAAA,CAAaW,UAAZC,WAAYD,EAAErB,CAAFqB,CAAbX,CAA7B;QAHTT,CAAAA;QAMAZ,OAAAa,wBAAAA,oBAAaR,OAAbQ;AAAAA,UAAAA;;;UAEEsB,IAAI,+CAA+CC,OAAAA,CAAO/B,OAAP+B;UACnD,KAAA,QAAkBD,CAAlB,CAAA;YAAA,OAAO;UAAP;UAEAE,WAAWF,CAACd,OAAAA,CAACV,CAADU,CAAGiB,MAAAA,CAAAA;UACfC,yBAAyB,CAAA,QAAAJ,CAACd,OAAAA,CAACH,CAADG,CAAD,CAAA,GAAA,CAAOc,CAACd,OAAAA,CAACH,CAADG,CAAGiB,MAAAA,CAAAA,CAAX,IAAA,CAAmB3B,CAAnB,CAAA;UACzB6B,sBAAsB,CAAA,QAAAL,CAACd,OAAAA,CAACoB,CAADpB,CAAD,CAAA,GAAA,CAAOc,CAACd,OAAAA,CAACoB,CAADpB,CAAGiB,MAAAA,CAAAA,CAAX,IAAA,CAAmBnB,EAAnB,CAAA;UACtBuB,oBAAoB,CAAA,QAAAP,CAACd,OAAAA,CAACsB,CAADtB,CAAD,CAAA,GAAA,CAAOc,CAACd,OAAAA,CAACsB,CAADtB,CAAGiB,MAAAA,CAAAA,CAAX,IAAA,CAAmBM,CAAnB,CAAA;UAEpB,IAAA,QAAGT,CAACd,OAAAA,CAACsB,CAADtB,CAAGwB,SAAAA,CAAAA,CAAP,CAAA;YACEC,wBAAwB,EAAA,GAAA,CAAGX,CAACd,OAAAA,CAACV,CAADU,CAAJ,CAAA,GAAQR,QAAR,GAAA,CAAgB6B,iBAAhB;UAD1B;YAGEI,wBAAwBzC;UAH1B;UAOAU,eAAeC,eAAWC,eAAAA,CAAeoB,QAA1B,EAAoClB,EAAzBF;UAG1B8B,mBAA+BC,MAAZjC,YAAYiC,SAAAA,EAAAA,EAAAA,EAAZC,aAAsBC,CAAtBD;;YAAsB;YAAGE,OAAEC,OAAFF,CAAEE,EAAGb,sBAAHa,EAA3BH,CAAYD;UAC/BK,gBAA4BL,MAAZjC,YAAYiC,SAAAA,EAAAA,EAAAA,EAAZC,aAAsBC,CAAtBD;;YAAsB;YAAGE,OAAE3B,OAAF0B,CAAE1B,EAAGgB,mBAAHhB,EAA3ByB,CAAYD;UAC5BM,iBAA6BN,MAAZjC,YAAYiC,SAAAA,EAAAA,EAAAA,EAAZC,aAAsBC,CAAtBD,EAAAE;;;YAAsB;YAAG,IAAA,QAAA7C,CAAAA,YAAA,CAAA,QAAAiD,CAAAA,YAAGC,OAAFN,CAAEM,EAAEjB,sBAAFiB,CAAHD,CAAA,CAAA,GAAA,CAAmCH,OAAFF,CAAEE,EAAGV,iBAAHU,CAAnC,IAAA,CAAA,SAAA,CAAA,CAAA9C,CAAA,CAAA;cAA4D6C,OAAEM,OAAFP,CAAEO,EAAEjB,mBAAFiB;YAA9D;cAAAN,OAAA;YAAA,EAAzBF,CAAYD;UAE7BU,yBAAyBX;UACzBY,sBAAsBN;UAGtBO,SAAS,CAACb,gBAAD,EAAmBM,aAAnB,CAAiCQ,KAAAA,CAAAA;UAC1Cd,mBAAiBf,UAAjBe,gBAAiBf,EAAG4B,MAAH5B;UACjBqB,gBAAcrB,UAAdqB,aAAcrB,EAAG4B,MAAH5B;UAGd8B,YAA2BnC,SAAf2B,cAAe3B,EAAoBoC,UAAjBhB,gBAAiBgB,EAAE7C,CAAF6C,CAApBpC;UAC3BqC,YAA0BR,OAAdH,aAAcG,EAAElC,CAAFkC;UAG1B3C,OAAkBoD,MAAlBC,IAAAC,YAAAD,WAAcE,KAAAA,CA